-- 068_platform_config_enums.sql
-- Platform-wide enum_values seeds + drop rigid CHECK constraints (varchar domains).
-- Regenerate inserts: node ad-west-api/scripts/gen-068-enum-sql.mjs

-- Drop CHECK constraints so values are configurable via enum_values.
-- Skips tables that do not exist yet (partial / older DB snapshots).
DO $$
DECLARE
  rec record;
BEGIN
  FOR rec IN
    SELECT * FROM (VALUES
      ('adwest', 'locations', 'chk_locations_level'),
      ('adwest', 'sthan_expenses', 'sthan_expenses_category_check'),
      ('adwest', 'sthan_expenses', 'sthan_expenses_status_check'),
      ('adwest', 'documents', 'chk_documents_access_level'),
      ('adwest', 'sreni_calendar_events', 'chk_sreni_calendar_scope'),
      ('adwest', 'report_submissions', 'chk_report_submissions_status'),
      ('adwest', 'report_template_fields', 'chk_report_template_field_type'),
      ('adwest', 'programs', 'chk_programs_status'),
      ('adwest', 'registrations', 'chk_registration_status'),
      ('adwest', 'attendance', 'chk_attendance_status'),
      ('adwest', 'approval_items', 'chk_approval_items_status'),
      ('adwest', 'approval_workflows', 'chk_approval_workflow_target_type'),
      ('adwest', 'report_metric_definitions', 'chk_report_metric_definitions_scope'),
      ('adwest', 'analytics_studio_layouts', 'chk_analytics_studio_layouts_type'),
      -- From 067 — household domains (safe to run even if 067 was skipped)
      ('adwest', 'srenies', 'chk_srenies_enrollment_scope'),
      ('adwest', 'srenies', 'chk_srenies_primary_contact_strategy'),
      ('adwest', 'household_members', 'chk_household_members_role'),
      ('adwest', 'household_members', 'chk_household_members_source')
    ) AS t(schema_name, table_name, constraint_name)
  LOOP
    IF EXISTS (
      SELECT 1 FROM information_schema.tables
      WHERE table_schema = rec.schema_name AND table_name = rec.table_name
    ) THEN
      EXECUTE format(
        'ALTER TABLE %I.%I DROP CONSTRAINT IF EXISTS %I',
        rec.schema_name, rec.table_name, rec.constraint_name
      );
    END IF;
  END LOOP;
END;
$$;

ON CONFLICT (enum_type, value) DO UPDATE SET
  label = EXCLUDED.label,
  sort_order = EXCLUDED.sort_order,
  parent_value = EXCLUDED.parent_value,
  active = true,
  updated_at = EXCLUDED.updated_at;
